const text = $input.first().json.message.text.trim();

const result = {
  command: null,
  game: null,
  content: null,
  error: null
};

// Разбиваем по "|"
const parts = text.split('|').map(p => p.trim());
const commandPart = parts[0];
const contentPart = parts[1] || null;

// Парсим команду и аргумент
const tokens = commandPart.split(/\s+/);
const command = tokens[0]?.toLowerCase();
const game = tokens.slice(1).join(' ').toLowerCase() || null; // <-- исправление тут

switch (command) {
  case '/games':
    result.command = 'games';
    break;

  case '/prompt':
    if (!game) {
      result.error = 'Укажите название игры: /prompt dota2';
    } else {
      result.command = 'prompt';
      result.game = game;
    }
    break;

  case '/add':
    if (!game || !contentPart) {
      result.error = 'Формат: /add название | текст промпта';
    } else {
      result.command = 'add';
      result.game = game;
      result.content = contentPart;
    }
    break;

  case '/edit':
    if (!game || !contentPart) {
      result.error = 'Формат: /edit название | новый текст';
    } else {
      result.command = 'edit';
      result.game = game;
      result.content = contentPart;
    }
    break;

  case '/rename':
    if (!game || !contentPart) {
      result.error = 'Формат: /rename старое | новое';
    } else {
      result.command = 'rename';
      result.game = game;
      result.content = contentPart.toLowerCase();
    }
    break;

  case '/test':
    if (!game) {
      result.error = 'Укажите название игры: /test dota2';
    } else {
      result.command = 'test';
      result.game = game;
      result.content = contentPart;
    }
    break;

  default:
    result.error = 'Неизвестная команда. Доступно: /games, /prompt, /add, /edit, /rename, /test';
}

return { json: result };

const rows = $input.all();

if (rows.length === 0) {
  return { json: { text: 'Нет сохранённых сегментов' } };
}

const games = rows.map(r => r.json.Сегмент);
const text = `Доступные сегменты (${games.length}):\n\n` + games.map(g => `• ${g}`).join('\n');

return { json: { text } };

const rows = $input.all();
const game = $('Command Parser').first().json.game;
const content = $('Command Parser').first().json.content;

const exists = rows.find(r => r.json.Сегмент.toLowerCase() === game);

if (exists) {
  return { json: { success: false, text: `Сегмент "${game}" уже существует. Используй /edit для изменения` } };
}

return { json: { success: true, game, content } };

const rows = $input.all();
const game = $('Command Parser').first().json.game;

const found = rows.find(r => r.json.Сегмент.toLowerCase() === game);

if (!found) {
  return { json: { text: `Сегмент "${game}" не найден` } };
}

const text = `📌 ${found.json.Сегмент}\n\n${found.json.Промпт}`;

return { json: { text } };

const rows = $input.all();
const game = $('Command Parser').first().json.game;
const content = $('Command Parser').first().json.content;

const found = rows.find(r => r.json.Сегмент.toLowerCase() === game);

if (!found) {
  return { json: { success: false, text: `Сегмент "${game}" не найден` } };
}

return { 
  json: { 
    success: true, 
    game,
    content,
    row_number: found.json.row_number
  } 
};

const rows = $input.all();
const oldName = $('Command Parser').first().json.game;
const newName = $('Command Parser').first().json.content;

const oldExists = rows.find(r => r.json.Сегмент.toLowerCase() === oldName);
const newExists = rows.find(r => r.json.Сегмент.toLowerCase() === newName);

if (!oldExists) {
  return { json: { success: false, text: `Сегмент "${oldName}" не найден` } };
}

if (newExists) {
  return { json: { success: false, text: `Сегмент "${newName}" уже занят` } };
}

return { 
  json: { 
    success: true, 
    oldName,
    newName,
    row_number: oldExists.json.row_number
  } 
};

const rows = $input.all();
const game = $('Command Parser').first().json.game;
const customInput = $('Command Parser').first().json.content; // может быть null

const found = rows.find(r => r.json.Сегмент.toLowerCase() === game);

if (!found) {
  return { json: { success: false, text: `Сегмент "${game}" не найден` } };
}

return { 
  json: { 
    success: true,
    game,
    prompt: found.json.Промпт,
    input: customInput || 'Тестовый запрос' // дефолтный если не указан
  } 
};

